/**
 * BFF Banner 组件
 * - 显示在 Home 页顶部
 * - 需要完成第二笔提现后才显示
 * - 点击文案区域进入 Dashboard，点击 View 按钮进入 Dashboard
 */

import { useEffect, useCallback } from "react";
import { useNavigate } from "react-router-dom";
import { useBffOverviewStore } from "@/stores/bffStore";
import { getBffOverview } from "@/api/bff";
import earningsImg from "@/assets/images/bff/money-bag-icon.png";
import bannerBg from "@/assets/images/bff/banner-bg.png";

export const BffBanner = () => {
  const navigate = useNavigate();
  const { overview, loading, setOverview, setLoading } = useBffOverviewStore();

  // rerender-use-callback: 稳定 fetchOverview 引用，供两个 useEffect 共用
  const fetchOverview = useCallback(async () => {
    setLoading(true);
    try {
      const data = await getBffOverview();
      setOverview(data);
    } catch (error) {
      console.error("[BffBanner] Failed to fetch overview:", error);
    } finally {
      setLoading(false);
    }
  }, [setOverview, setLoading]);

  // 进入页面时初始加载，loading 互斥防止重复请求
  useEffect(() => {
    if (!overview && !loading) fetchOverview();
  }, [overview, loading, fetchOverview]);

  if (loading || !overview) {
    return null;
  }

  return (
    <div
      className="relative flex items-center gap-3 rounded-[16px] px-4 py-3 mb-4 cursor-pointer overflow-hidden"
      style={{
        backgroundImage: `url(${bannerBg})`,
        backgroundSize: "cover",
        backgroundPosition: "center",
      }}
      onClick={() => navigate("/bff-dashboard")}
    >
      {/* 左侧钱袋插画 */}
      <img src={earningsImg} alt="" className="shrink-0 w-[52px] h-[52px] object-contain" />

      {/* 中间文案 */}
      <div className="flex-1 min-w-0">
        <p className="text-[16px] font-bold leading-[20px] text-white">
          Gift your girls ${overview.bannerGiftAmount ?? 20}
        </p>
        <p className="text-[13px] leading-[18px] text-white/80 mt-0.5">
          Get ${overview.bannerRewardAmount ?? 60} back!
        </p>
      </div>

      {/* 右侧 View 按钮 */}
      <button
        className="shrink-0 flex items-center justify-center h-[34px] px-5 bg-white rounded-full"
        onClick={(e) => {
          e.stopPropagation();
          navigate("/bff-dashboard");
        }}
      >
        <span className="text-[14px] font-semibold text-[#55C8F2] leading-5 whitespace-nowrap">View</span>
      </button>
    </div>
  );
};
