import { useEffect } from "react";
import { useLocation } from "react-router-dom";
import { useApkPrompt } from "@/hooks/useApkPrompt";
import { isApp } from "@/utils/bridge";
import { openInToolApp } from "@/utils/openApk";
import TopBar from "@/components/TopBar";
import { BffBanner } from "@/components/BffBanner";
import { useCashout } from "@/hooks/useCashout";
import { CashoutStage } from "@/types/cashout";
import { getStageIndex } from "@/utils/cashoutUtils";
import { OnboardingTaskList } from "./OnboardingTaskList";
import { DailyTaskList } from "./DailyTaskList";
import { CashoutTaskList } from "./CashoutTaskList";
import { bpTrack } from "@/tracking";
import { EventName } from "@/tracking/events";

export default function Home() {
  const { pathname } = useLocation();

  // 非 APK 环境进入 Home 页时尝试跳转 APK
  useEffect(() => {
    if (!isApp()) {
      openInToolApp();
    }
  }, []);

  // 埋点：首页展示（tab 切回时重新触发）
  useEffect(() => {
    if (pathname !== "/") return;
    bpTrack(EventName.pwa_home_page_show);
    bpTrack(EventName.pwa_home_page_tab_show);
  }, [pathname]);

  // StageTwo 完成后每天弹一次 APK 下载弹窗
  useApkPrompt();

  const { willCashoutStage } = useCashout();
  const hasCompletedW2 = getStageIndex(willCashoutStage) >= getStageIndex(CashoutStage.StageThree);

  return (
    <div className="h-full bg-surface overflow-y-auto">
      {/* 顶部导航 */}
      <TopBar showProgress={true} />

      {/* 主内容区域 */}
      <div className="px-4 pt-5 pb-8">
        {/* BFF 裂变 Banner - 完成第二笔提现后常驻 */}
        {hasCompletedW2 && <BffBanner />}

        {/* Cashout 任务列表 */}
        <CashoutTaskList />

        {/* Onboarding 任务列表 */}
        <OnboardingTaskList />

        {/* Daily 任务列表 */}
        <DailyTaskList />
      </div>
    </div>
  );
}
